#ifdef cl_khr_fp64
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

__kernel void lud_diagonal(__global float *m,
                           __local float *shadow,
                           int matrix_dim,
                           int offset)
{
    int tx = (int)get_local_id(0);

    for (int j = 0; j < BLOCK_SIZE; j++) {
        shadow[tx * BLOCK_SIZE + j] = m[(offset + tx) * matrix_dim + (offset + j)];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    for (int i = 0; i < BLOCK_SIZE; i++) {
        if (tx >= i) {
            float sum = shadow[i * BLOCK_SIZE + tx];
            for (int k = 0; k < i; k++) {
                sum -= shadow[i * BLOCK_SIZE + k] * shadow[k * BLOCK_SIZE + tx];
            }
            shadow[i * BLOCK_SIZE + tx] = sum;
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        if (tx > i) {
            float sum = shadow[tx * BLOCK_SIZE + i];
            for (int k = 0; k < i; k++) {
                sum -= shadow[tx * BLOCK_SIZE + k] * shadow[k * BLOCK_SIZE + i];
            }
            shadow[tx * BLOCK_SIZE + i] = sum / shadow[i * BLOCK_SIZE + i];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int j = 0; j < BLOCK_SIZE; j++) {
        m[(offset + tx) * matrix_dim + (offset + j)] = shadow[tx * BLOCK_SIZE + j];
    }
}

__kernel void lud_perimeter(__global float *m,
                            __local float *dia,
                            __local float *peri_row,
                            __local float *peri_col,
                            int matrix_dim,
                            int offset)
{
    int tx = (int)get_local_id(0);
    int bx = (int)get_group_id(0);

    int blk = offset + BLOCK_SIZE * (bx + 1);

    if (tx < BLOCK_SIZE) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            dia[tx * BLOCK_SIZE + j]      = m[(offset + tx) * matrix_dim + (offset + j)];
            peri_row[tx * BLOCK_SIZE + j] = m[(offset + tx) * matrix_dim + (blk + j)];
            peri_col[tx * BLOCK_SIZE + j] = m[(blk + tx) * matrix_dim + (offset + j)];
        }
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    for (int i = 0; i < BLOCK_SIZE; i++) {
        if (tx < BLOCK_SIZE) {
            float sum = 0.0f;
            for (int k = 0; k < i; k++) {
                sum += dia[i * BLOCK_SIZE + k] * peri_row[k * BLOCK_SIZE + tx];
            }
            peri_row[i * BLOCK_SIZE + tx] -= sum;
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (tx < BLOCK_SIZE) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (int k = 0; k < j; k++) {
                sum += peri_col[tx * BLOCK_SIZE + k] * dia[k * BLOCK_SIZE + j];
            }
            peri_col[tx * BLOCK_SIZE + j] =
                (peri_col[tx * BLOCK_SIZE + j] - sum) / dia[j * BLOCK_SIZE + j];
        }
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (tx < BLOCK_SIZE) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            m[(offset + tx) * matrix_dim + (blk + j)] = peri_row[tx * BLOCK_SIZE + j];
            m[(blk + tx) * matrix_dim + (offset + j)] = peri_col[tx * BLOCK_SIZE + j];
        }
    }
}

__kernel void lud_internal(__global float *m,
                           __local float *peri_row,
                           __local float *peri_col,
                           int matrix_dim,
                           int offset)
{
    int tx = (int)get_local_id(0);
    int ty = (int)get_local_id(1);

    int bx = (int)get_group_id(0);
    int by = (int)get_group_id(1);

    int global_col = offset + BLOCK_SIZE * (bx + 1);
    int global_row = offset + BLOCK_SIZE * (by + 1);

    peri_row[ty * BLOCK_SIZE + tx] = m[(offset + ty) * matrix_dim + (global_col + tx)];
    peri_col[ty * BLOCK_SIZE + tx] = m[(global_row + ty) * matrix_dim + (offset + tx)];
    barrier(CLK_LOCAL_MEM_FENCE);

    float sum = 0.0f;
    for (int k = 0; k < BLOCK_SIZE; k++) {
        sum += peri_col[ty * BLOCK_SIZE + k] * peri_row[k * BLOCK_SIZE + tx];
    }

    m[(global_row + ty) * matrix_dim + (global_col + tx)] -= sum;
}
